#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, X, K;
        scanf("%lld %lld %lld", &N, &X, &K);
        if(N * X <= K) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

